161. /// <summary>
162. /// Default ordinalizer providing English ordinal suffixes (1st, 2nd, 3rd, etc.).
163. /// </summary>
164. public class DefaultOrdinalizer : IOrdinalizer
165. {
166.     /// <inheritdoc />
167.     public virtual string Convert(int number, string numberString)
168.     {
169.         var suffix = (number % 100) switch
170.         {
171.             11 or 12 or 13 => "th",
172.             _ => (number % 10) switch
173.             {
174.                 1 => "st",
175.                 2 => "nd",
176.                 3 => "rd",
177.                 _ => "th"
178.             }
179.         };
180. 
181.         return numberString + suffix;
182.     }
183. }
